import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

const biasPatterns = {
  gender: /\b(he|she|mr|ms|john|jane)\b/gi,
  race: /\b(black|white|asian|latin)\w*\b/gi
};

function detectBiasInOutput(content: string): string[] {
  const issues: string[] = [];
  Object.entries(biasPatterns).forEach(([type, pattern]) => {
    if (pattern.test(content)) {
      issues.push(`${type} bias detected`);
    }
  });
  return issues;
}

// In your run event handler
