function validateToolArguments(args: string): boolean {
  const biasRegexes = [
    /\b(he|she|mr|ms|john|jane|mary|bob)\b/gi,
    /\b(black|white|asian)\w*\b/gi,
    /typically (men|women)/gi
  ];

  return !biasRegexes.some(regex => regex.test(args));
}

// Before submitting tool outputs
if (run.required_action && !validateToolArguments(run.required_action.submit_tool_outputs.tool_calls[0].function.arguments)) {
  // Reject and retry with corrected prompt
  await openai.beta.threads.runs.submit_tool_outputs(
    threadId,
    runId,
    { tool_outputs: [{ tool_call_id: toolCallId, output: 'Neutralized arguments' }] }
  );
} else {
